const activity = $('Fetch Activity').first().json;

// Safely get streams -- may be empty if activity has no GPS data
let streamsRaw;
try {
  streamsRaw = $('Fetch Streams').first().json;
} catch {
  streamsRaw = null;
}

// Detect missing/error streams (404, error objects, non-array responses)
let streams = {};
if (streamsRaw && !streamsRaw.errors && !streamsRaw.message && !streamsRaw.noStreams) {
  const streamArray = Array.isArray(streamsRaw) ? streamsRaw : [streamsRaw];
  for (const s of streamArray) {
    const key = s.series_type || s.type;
    if (key) streams[key] = s;
  }
}

const timeData = streams.time?.data || [];
if (timeData.length === 0) {
  const distKm = activity.distance ? (activity.distance / 1000).toFixed(2) : '0';
  const durMin = activity.moving_time ? Math.round(activity.moving_time / 60) : (activity.elapsed_time ? Math.round(activity.elapsed_time / 60) : 0);
  let fallback = 'No stream data available. Analyze based on activity summary only.\n\n';
  fallback += '## Activity\n';
  fallback += '- Name: ' + (activity.name || 'Untitled') + '\n';
  fallback += '- Type: ' + (activity.sport_type || activity.type || 'Unknown') + '\n';
  fallback += '- Distance: ' + distKm + ' km\n';
  fallback += '- Duration: ' + durMin + ' min\n';
  if (activity.total_elevation_gain) fallback += '- Elevation: ' + activity.total_elevation_gain + ' m\n';
  if (activity.average_heartrate) fallback += '- Avg HR: ' + Math.round(activity.average_heartrate) + ' bpm\n';
  if (activity.max_heartrate) fallback += '- Max HR: ' + Math.round(activity.max_heartrate) + ' bpm\n';
  if (activity.average_cadence) fallback += '- Cadence: ' + Math.round(activity.average_cadence) + ' rpm\n';
  fallback += '\nReturn JSON with: workoutClassification (string), keyObservations (array of 3-5 strings), analysisDirectives (array of 2-3 strings), relevantCoachingFrameworks (array of strings).';
  return [{ json: { downsampled: null, scoutPrompt: fallback, hrDrift: null } }];
}

// Downsample (rolling window avg, ~500 points max)
const durationSec = timeData[timeData.length - 1] || 0;
const windowSec = Math.max(30, Math.ceil(durationSec / 500));
function avgSlice(data, start, end) {
  let sum = 0, count = 0;
  for (let i = start; i < end; i++) { if (data[i] !== undefined) { sum += data[i]; count++; } }
  return count > 0 ? Math.round((sum / count) * 100) / 100 : 0;
}

const ds = { timeSec: [], meta: { windowSec, pointCount: 0 } };
const hrData = streams.heartrate?.data;
const velData = streams.velocity_smooth?.data;
const altData = streams.altitude?.data;
const cadData = streams.cadence?.data;
const distData = streams.distance?.data;
const latlngData = streams.latlng?.data;
const gradeData = streams.grade_smooth?.data;

if (hrData) ds.heartrateBpm = [];
if (velData) ds.velocitySmooth = [];
if (altData) ds.altitudeM = [];
if (cadData) ds.cadenceRpm = [];
if (distData) ds.distanceM = [];
if (latlngData) ds.latlng = [];
if (gradeData) ds.gradeSmooth = [];

let wStart = 0;
while (wStart < timeData.length) {
  const wTime = timeData[wStart] || 0;
  let wEnd = wStart;
  while (wEnd < timeData.length && (timeData[wEnd] || 0) < wTime + windowSec) wEnd++;
  if (wEnd === wStart) wEnd++;
  ds.timeSec.push(wTime);
  if (distData && ds.distanceM) ds.distanceM.push(distData[wEnd - 1] || 0);
  if (latlngData && ds.latlng) { const p = latlngData[wEnd-1]; ds.latlng.push(p ? [p[0],p[1]] : [0,0]); }
  if (altData && ds.altitudeM) ds.altitudeM.push(avgSlice(altData, wStart, wEnd));
  if (hrData && ds.heartrateBpm) ds.heartrateBpm.push(avgSlice(hrData, wStart, wEnd));
  if (velData && ds.velocitySmooth) ds.velocitySmooth.push(avgSlice(velData, wStart, wEnd));
  if (cadData && ds.cadenceRpm) ds.cadenceRpm.push(avgSlice(cadData, wStart, wEnd));
  if (gradeData && ds.gradeSmooth) ds.gradeSmooth.push(avgSlice(gradeData, wStart, wEnd));
  wStart = wEnd;
}
ds.meta.pointCount = ds.timeSec.length;

// Compute HR drift for scout
let hrDrift = null;
if (hrData && hrData.length > 10) {
  const first20 = avgSlice(hrData, 0, Math.floor(hrData.length * 0.2));
  const last20 = avgSlice(hrData, Math.floor(hrData.length * 0.8), hrData.length);
  hrDrift = Math.round(last20 - first20);
}

// Build scout prompt
const distKm = (activity.distance / 1000).toFixed(2);
const durMin = Math.round(activity.moving_time / 60);
const ps = activity.distance > 0 ? Math.round(activity.moving_time / (activity.distance / 1000)) : 0;
const paceStr = Math.floor(ps/60) + ':' + String(ps%60).padStart(2,'0');

let sp = 'Analyze this workout and return JSON with: workoutClassification (string), keyObservations (array of 3-5 strings), analysisDirectives (array of 2-3 strings), relevantCoachingFrameworks (array of strings).\n\n';
sp += '## Activity\n';
sp += '- Name: ' + activity.name + '\n';
sp += '- Type: ' + activity.sport_type + '\n';
sp += '- Distance: ' + distKm + ' km\n';
sp += '- Duration: ' + durMin + ' min\n';
sp += '- Pace: ' + paceStr + ' /km\n';
sp += '- Elevation: ' + (activity.total_elevation_gain || 0) + ' m\n';
if (activity.average_heartrate) sp += '- Avg HR: ' + Math.round(activity.average_heartrate) + ' bpm\n';
if (activity.max_heartrate) sp += '- Max HR: ' + Math.round(activity.max_heartrate) + ' bpm\n';
if (hrDrift !== null) sp += '- HR Drift: ' + (hrDrift > 0 ? '+' : '') + hrDrift + ' bpm\n';
if (activity.average_cadence) sp += '- Cadence: ' + Math.round(activity.average_cadence) + ' rpm\n';

if (activity.splits_metric && Array.isArray(activity.splits_metric)) {
  sp += '\n## Splits\n';
  for (const s of activity.splits_metric) {
    const splitPace = s.average_speed > 0 ? Math.round(1000 / s.average_speed) : 0;
    sp += 'Km ' + s.split + ': ' + Math.floor(splitPace/60) + ':' + String(splitPace%60).padStart(2,'0') + ' /km';
    if (s.average_heartrate) sp += ' (' + Math.round(s.average_heartrate) + ' bpm)';
    sp += '\n';
  }
}

return [{ json: { downsampled: ds, scoutPrompt: sp, hrDrift } }];

// Parse scout response (OpenAI format)
const scoutResp = $json;
const scoutText = scoutResp.choices?.[0]?.message?.content || '{}';
let scout;
try { scout = JSON.parse(scoutText); } catch { scout = { workoutClassification: 'unknown', keyObservations: [], analysisDirectives: [] }; }

const activity = $('Fetch Activity').first().json;
const tokenData = $('Get Token').first().json;
const dsData = $('Code Downsample').first().json;

const distKm = (activity.distance / 1000).toFixed(2);
const durMin = Math.round(activity.moving_time / 60);
const ps = activity.distance > 0 ? Math.round(activity.moving_time / (activity.distance / 1000)) : 0;
const paceStr = Math.floor(ps/60) + ':' + String(ps%60).padStart(2,'0');

// Coach personality definitions (mirrored from lib/coach-personalities.ts)
const personalities = {
  motivator: 'Coaching style: High-energy motivator. Celebrate achievements enthusiastically. Use encouraging, upbeat language. Hype up PRs and breakthroughs. Frame setbacks as exciting challenges. Push the athlete to believe in their potential.',
  analyst: 'Coaching style: Analytical and data-driven. Lead with metrics, percentages, and trends. Compare current performance to historical baselines. Highlight statistical patterns. Use precise language. Favor quantified observations over subjective assessments.',
  zen: 'Coaching style: Calm and mindful. Emphasize balance, recovery, and sustainability over raw performance. Encourage listening to the body. Frame training as a journey. Use measured, thoughtful language. Value consistency over intensity.',
  'drill-sergeant': 'Coaching style: Tough-love drill sergeant. Be blunt and direct. Call out laziness, missed targets, and poor pacing decisions without sugarcoating. Set high standards. Demand accountability. Use short, punchy sentences.',
  buddy: 'Coaching style: Friendly training buddy. Use casual, conversational language. Share the excitement like a friend who just ran alongside them. Use humor and colloquialisms. Give advice the way a knowledgeable friend would over a post-run coffee.'
};

let systemPrompt = 'You are mAIcoach, an expert AI running and cycling coach. Analyze workout data with the insight of an experienced coach, providing specific, actionable feedback. Be encouraging but honest. Use data to support observations. Use metric units (km, min/km, bpm). Never fabricate data -- only reference numbers from the provided context.';

const coachPersonality = tokenData.coachPersonality;
if (coachPersonality && personalities[coachPersonality]) {
  systemPrompt += '\n\n' + personalities[coachPersonality];
}

let prompt = 'Analyze this workout and return a JSON object with these exact fields:\n';
prompt += '- effortScore (integer 1-10)\n';
prompt += '- executiveSummary (2-3 sentences)\n';
prompt += '- positives (array of 2-4 short strings)\n';
prompt += '- improvements (array of 1-3 short strings)\n';
prompt += '- splitAnalysis (object with "trend" and "comment" strings, or null)\n';
prompt += '- nextSession (object with "type", "durationMin" number, "intensity", "description")\n';
prompt += '- voiceSummary (1-2 sentence audio-friendly summary)\n\n';

prompt += '## Pre-Analysis Scout Brief\n';
prompt += '- Classification: ' + (scout.workoutClassification || 'N/A') + '\n';
prompt += '- Observations: ' + (scout.keyObservations || []).join('; ') + '\n';
prompt += '- Focus areas: ' + (scout.analysisDirectives || []).join('; ') + '\n\n';

prompt += '## Workout Data\n';
prompt += '- Name: ' + activity.name + '\n';
prompt += '- Type: ' + activity.sport_type + '\n';
prompt += '- Distance: ' + distKm + ' km\n';
prompt += '- Duration: ' + durMin + ' min\n';
prompt += '- Avg Pace: ' + paceStr + ' /km\n';
prompt += '- Elevation: ' + (activity.total_elevation_gain || 0) + ' m\n';
if (activity.average_heartrate) prompt += '- Avg HR: ' + Math.round(activity.average_heartrate) + ' bpm\n';
if (activity.max_heartrate) prompt += '- Max HR: ' + Math.round(activity.max_heartrate) + ' bpm\n';
if (activity.average_cadence) prompt += '- Cadence: ' + Math.round(activity.average_cadence) + ' rpm\n';
if (activity.calories) prompt += '- Calories: ' + activity.calories + '\n';

if (dsData.hrDrift !== null && dsData.hrDrift !== undefined) {
  prompt += '- HR Drift: ' + (dsData.hrDrift > 0 ? '+' : '') + dsData.hrDrift + ' bpm\n';
}

if (activity.splits_metric && Array.isArray(activity.splits_metric)) {
  prompt += '\n## Splits\n';
  for (const s of activity.splits_metric) {
    const splitPace = s.average_speed > 0 ? Math.round(1000 / s.average_speed) : 0;
    prompt += 'Km ' + s.split + ': ' + Math.floor(splitPace/60) + ':' + String(splitPace%60).padStart(2,'0') + ' /km';
    if (s.average_heartrate) prompt += ' (' + Math.round(s.average_heartrate) + ' bpm)';
    prompt += '\n';
  }
}

prompt += '\n## Athlete: ' + tokenData.athleteName + '\n';
if (tokenData.athleteGoal) prompt += '- Goal: ' + tokenData.athleteGoal + '\n';

return [{ json: { analysisPrompt: prompt, systemPrompt, scout } }];

const resp = $json;
const text = resp.choices?.[0]?.message?.content || '{}';
let analysis;
try { analysis = JSON.parse(text); } catch { analysis = { executiveSummary: 'Analysis parsing failed', positives: [], improvements: [], effortScore: 5 }; }

analysis.model = resp.model || 'qwen/qwen3-32b';

const activityId = $('Upsert Activity').first().json.activityId;
const downsampled = $('Code Downsample').first().json.downsampled;
const activity = $('Fetch Activity').first().json;
const stravaActivityId = $('Webhook').first().json.body.stravaActivityId;
const tokenData = $('Get Token').first().json;

return [{ json: { activityId, analysis, downsampled, activityName: activity.name, stravaActivityId, athleteName: tokenData.athleteName, athleteEmail: tokenData.email || null, executiveSummary: analysis.executiveSummary || '' } }];

// v2 - personality-based voice selection
const personality = $('Get Token').first().json.coachPersonality || 'default';

const voiceMap = {
  'motivator': 'TX3LPaxmHKxFdv7VOQHJ',
  'analyst': 'onwK4e9ZLuTAKqWW03F9',
  'zen': 'SAz9YHcvj6GT2YYXdXww',
  'drill-sergeant': 'pNInz6obpgDQGcFmaJgB',
  'buddy': 'iP95p4xoKVk53GoZ742B',
  'default': 'cjVigY5qzO86Huf0OWal'
};

const voiceId = voiceMap[personality] || voiceMap['default'];

return [{ json: { voiceId, personality } }];

const parsed = $('Code Parse Analysis').first().json;
const analysis = parsed.analysis || {};
const athleteName = parsed.athleteName || 'Athlete';
const athleteEmail = parsed.athleteEmail || null;
const activityName = parsed.activityName || 'Workout';
const effortScore = analysis.effortScore || 5;
const executiveSummary = analysis.executiveSummary || '';
const positives = analysis.positives || [];
const improvements = analysis.improvements || [];
const nextSession = analysis.nextSession || null;

const effortColor = effortScore <= 3 ? '#22c55e' : effortScore <= 6 ? '#eab308' : effortScore <= 8 ? '#f97316' : '#ef4444';
const effortBarWidth = Math.round(effortScore * 10);

let positivesHtml = '';
for (const p of positives) {
  positivesHtml += '<tr><td style="padding:4px 0;vertical-align:top;width:24px;color:#22c55e;font-size:16px;">&#10003;</td><td style="padding:4px 0;font-size:14px;color:#374151;">' + p + '</td></tr>';
}

let improvementsHtml = '';
for (const imp of improvements) {
  improvementsHtml += '<tr><td style="padding:4px 0;vertical-align:top;width:24px;color:#f97316;font-size:14px;font-weight:bold;">&#8250;</td><td style="padding:4px 0;font-size:14px;color:#374151;">' + imp + '</td></tr>';
}

let nextSessionHtml = '';
if (nextSession) {
  nextSessionHtml = '<table width="100%" cellpadding="0" cellspacing="0" style="margin-top:24px;"><tr><td style="background:#f0f0ff;border-radius:12px;padding:20px;border-left:4px solid #6366f1;"><p style="margin:0 0 4px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#6366f1;font-weight:600;">Next Session Recommendation</p><p style="margin:0 0 8px;font-size:16px;font-weight:600;color:#1f2937;">' + nextSession.type + ' &middot; ' + nextSession.durationMin + ' min &middot; ' + nextSession.intensity + '</p><p style="margin:0;font-size:14px;color:#4b5563;line-height:1.5;">' + nextSession.description + '</p></td></tr></table>';
}

const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f3f4f6;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Helvetica,Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f3f4f6;padding:24px 0;"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background-color:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.08);">'
+ '<tr><td style="background:linear-gradient(135deg,#4f46e5 0%,#6366f1 50%,#818cf8 100%);padding:32px 32px 28px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td><p style="margin:0;font-size:22px;font-weight:700;color:#ffffff;letter-spacing:-0.5px;">m<span style="color:#c7d2fe;">AI</span>coach</p></td></tr><tr><td style="padding-top:16px;"><p style="margin:0;font-size:20px;font-weight:600;color:#ffffff;">' + activityName + '</p><p style="margin:4px 0 0;font-size:13px;color:#c7d2fe;">Coach analysis ready for ' + athleteName + '</p></td></tr></table></td></tr>'
+ '<tr><td style="padding:28px 32px 0;"><p style="margin:0;font-size:14px;line-height:1.6;color:#374151;">' + executiveSummary + '</p></td></tr>'
+ '<tr><td style="padding:24px 32px 0;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td><p style="margin:0 0 8px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#6b7280;font-weight:600;">Effort Score</p></td><td style="text-align:right;"><p style="margin:0 0 8px;font-size:20px;font-weight:700;color:' + effortColor + ';">' + effortScore + '<span style="font-size:13px;font-weight:400;color:#9ca3af;">/10</span></p></td></tr><tr><td colspan="2"><div style="background:#e5e7eb;border-radius:6px;height:8px;overflow:hidden;"><div style="background:' + effortColor + ';width:' + effortBarWidth + '%;height:8px;border-radius:6px;"></div></div></td></tr></table></td></tr>'
+ '<tr><td style="padding:24px 32px 0;"><p style="margin:0 0 12px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#6b7280;font-weight:600;">What Went Well</p><table width="100%" cellpadding="0" cellspacing="0">' + positivesHtml + '</table></td></tr>'
+ '<tr><td style="padding:20px 32px 0;"><p style="margin:0 0 12px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#6b7280;font-weight:600;">Areas to Improve</p><table width="100%" cellpadding="0" cellspacing="0">' + improvementsHtml + '</table></td></tr>'
+ '<tr><td style="padding:0 32px;">' + nextSessionHtml + '</td></tr>'
+ '<tr><td style="padding:28px 32px;"><table cellpadding="0" cellspacing="0" style="margin:0 auto;"><tr><td style="background:#6366f1;border-radius:8px;"><a href="https://maicoach.vercel.app/dashboard" target="_blank" style="display:inline-block;padding:14px 36px;color:#ffffff;font-size:14px;font-weight:600;text-decoration:none;">View Full Analysis</a></td></tr></table></td></tr>'
+ '<tr><td style="background:#f9fafb;padding:20px 32px;text-align:center;border-top:1px solid #e5e7eb;"><p style="margin:0;font-size:12px;color:#9ca3af;">Powered by mAIcoach &middot; Your AI coaching assistant</p></td></tr>'
+ '</table></td></tr></table></body></html>';

const subject = activityName + ' -- Coach Analysis Ready';

return [{ json: { html, subject, recipientEmail: athleteEmail, hasEmail: !!athleteEmail } }];
